def topological_sort(graph):
    in_degree = {node: 0 for node in graph}

    # Calculate the in-degree of each node
    for nodes in graph.values():
        for node in nodes:
            in_degree[node] += 1

    # Initialize the queue with all nodes having in-degree 0
    from collections import deque
    queue = deque([node for node, degree in in_degree.items() if degree == 0])

    top_order = []

    # Process until the queue is empty
    while queue:
        node = queue.popleft()
        top_order.append(node)

        # Decrease the in-degree of each dependent node and add to queue if in-degree becomes zero
        for dependent_node in graph[node]:
            in_degree[dependent_node] -= 1
            if in_degree[dependent_node] == 0:
                queue.append(dependent_node)

    # Check if there is a cycle (not all nodes are processed, i.e., |top_order| < number of nodes)
    if len(top_order) != len(in_degree):
        raise ValueError("Graph has at least one cycle.")

    return top_order
```

