def topological_sort(graph):
    from collections import deque

    # Calculate in-degree for each node
    in_degree = {node: 0 for node in graph}
    for dependencies in graph.values():
        for dependency in dependencies:
            in_degree[dependency] += 1

    # Initialize the queue with nodes that have no incoming edges
    zero_indegree_queue = deque([node for node, degree in in_degree.items() if degree == 0])

    sorted_order = []

    while zero_indegree_queue:
        node = zero_indegree_queue.popleft()
        sorted_order.append(node)

        # Decrease the in-degree of each neighbor by one
        for neighbor in graph[node]:
            in_degree[neighbor] -= 1

            # If a neighbor has no incoming edges, add it to the queue
            if in_degree[neighbor] == 0:
                zero_indegree_queue.append(neighbor)

    return sorted_order if len(sorted_order) == len(graph) else []
